//create page load listener
window.onload = init;
// Job card 
// ======================================================================
var job_card = document.getElementById("jobs_wrapper")
var filter_keyword = document.getElementById('filtered_keywords');

// var formHandle = document.forms.form_ship;
var searchForm = document.forms.search_form

// add new job
var addNewJobForm = document.getElementById("add_job_form");
// ======================================================================
var favJobs = [];
var jobs = [];
// Locations
var locations = [];
var roles = [];
var companies = [];
function init() {

    // Localstorage test
    console.log(JSON.parse(localStorage.getItem("SavedJobs")));

    // Form 
    // FORM CHECK
    searchForm.onsubmit = mySearch; // Search Constraint
    // End POINT
    const endpoint = './assets/json/data.json';
    var xhr = new XMLHttpRequest();
    xhr.open('GET', endpoint, true);
    xhr.responseType = 'json';
    xhr.onload = function () {
        if (xhr.status === 200) {
            const data = xhr.response;
            jobs = data.jobs;
            // Default Job Card
            jobCard(jobs)
            dropDownList(jobs);
            // Role List
            dataList(jobs);
        } else {
            job_card.innerHTML += `<p>Failed Loading</p>`;
        }
    };
    // console.log(jobs);
    xhr.send(null);
}

// Job Cards
function jobCard(jobs) {
    const total_jobs = document.getElementById('home_total_jobs')
    total_jobs.innerHTML = `<p> Total ${jobs.length} jobs posted: today`

    // IMPORTANT: clear old content first
    job_card.innerHTML = "";
    // content
    jobs.forEach(job => {
        // <i class="fa-solid fa-star"></i>
        // Jobs cards
        job_card.innerHTML += `
        <a href="job.html?job_id=${job.id}" style="color:inherit">
<div class="job_card">
<i class="fa-regular fa-star icon"></i>
              <div class="logo">
                <img src="./assets/img/company/${job.logo}" alt="" />
              </div>
                <div class="job_details">
                <h3 class="">${job.role}</h3>
                <h4 class="company">${job.company}</h4>
                <div class="location_type">
                  <span class="badge">${job.location}</span>
                  <span class="badge1">${job.type}</span>
                  <p class="description">${job.description}
                  </p>
                  <p class="ago">${job.posted}</p>
                </div>
              </div>
              </div>
              </a>
            `;
    });
    // Getting all the icons from the job
    const icons = job_card.querySelectorAll(".icon");

    let clickCount = 0;
    // icons[1].addEventListener("click", (e) => {
    //     e.preventDefault();
    //     console.log(icons[1])

    // })
    icons.forEach((icon, index) => {
        icon.addEventListener("click", (e) => {
            clickCount++;
            e.preventDefault();
            if (clickCount % 2 === 0) {
                icons[index].classList.remove("fa-solid");
                icons[index].style.color = '';
                icons[index].classList.add("fa-regular");
            } else {
                icons[index].classList.remove("fa-regular");
                icons[index].style.color = 'orange';
                icons[index].classList.add("fa-solid");
            }
            // Save and Push to the localstorage jobs
            favJobs.push(jobs[index]);
            // Saving it to the localstorage
            localStorage.setItem("SavedJobs", JSON.stringify(favJobs));
        });
    });
}

// Job Filter
function jobFilter() {
    const role = document.getElementById("roleList").value;
    const location = document.getElementById("locationList").value;
    const company = document.getElementById("companyList").value;
    const sortJobs = jobs.filter(job => {
        return (
            (role === "" || job.role === role) &&
            (location === "" || job.location === location) &&
            (company === "" || job.company === company)
        );
    });
    // Add the filtered keyword for the better UI
    filter_keyword.innerHTML = `
    ${role ? `<span class="role_badge">${role}</span> ` : ''}
    ${location ? `<span class="location_badge">${location}</span> ` : ''}
    ${company ? `<span class="company_badge">${company}</span> ` : ''}`
    jobCard(sortJobs)
}
// =============== Lists ========================
function dropDownList(jobs) {
    var companyList = document.getElementById("companyList");
    var locationList = document.getElementById("locationList");
    var roleList = document.getElementById("roleList");
    // Push Types
    jobs.forEach(job => {
        locations = [...new Set(jobs.map(job => job.location))]
        roles = [...new Set(jobs.map(job => job.role))];
        companies = [...new Set(jobs.map(job => job.company))]
    });
    // Company
    companies.forEach(company => {
        companyList.innerHTML += `
            <option value="${company}">${company}</option>
        `;
    });
    // Roles
    roles.forEach(role => {
        roleList.innerHTML += `
            <option value="${role}">${role}</option>
        `;
    });
    // Locations
    locations.forEach(location => {
        locationList.innerHTML += `
            <option value="${location}">${location}</option>
        `;
    });
}


// Search Constrain Function
function mySearch() {
    // Check the empty search
    if (searchForm.role.value === '') {
        searchForm.role.classList.add('input_error');
        searchForm.role.placeholder = "Please enter a job role";
        return false;
    }
    if (searchForm.location.value === '') {
        searchForm.location.classList.add('input_error');
        searchForm.location.placeholder = "Please enter a Location";
        return false;

    }
}

// Data List for the Role and Location
function dataList(jobs) {
    const roles = document.getElementById('role_suggestions');
    const locations = document.getElementById('location_suggestions');
    // Unique Roles
    const uniqueRoles = [...new Set(jobs.map(job => job.role))];
    uniqueRoles.forEach(role => {
        const option = document.createElement('option');
        option.value = role;
        roles.appendChild(option);
    });
    // Unique Companies
    const uniqueCompanies = [...new Set(jobs.map(job => job.location))];
    uniqueCompanies.forEach(location => {
        const option = document.createElement('option');
        option.value = location;
        locations.appendChild(option);
    });
}

// onclick="toggleBox()"
function showHideForm() {

    if (addNewJobForm.style.display === 'inline') {
        addNewJobForm.style.display = 'none';
    } else {

        addNewJobForm.style.display = 'inline'
    }
}

